var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"VOICE_NPC_NULL_NULL","text":{"KOREA":"돌아와.","JPN":"帰ってきて。","ENG":"Come back.","TWN":"回來吧。"},"stage":{"bg":"HANOK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"VOICE_NPC_NULL_NULL","text":{"KOREA":"돌아와서 기억해내는 거야. 당신이 저버린 것들을.","JPN":"帰ってきて、思い出して。あなたが捨てたものを。","ENG":"Come back and remember what you turned your back on.","TWN":"回來，然後記起你所拋棄的一切。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"VOICE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"악몽이라도 꾼 안색이군.","JPN":"悪夢でも見たような顔色だな。","ENG":"You look like you had a nightmare.","TWN":"你的臉色看起來像做了惡夢。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"눈을 뜨자마자 보는 게 그대일 줄은 몰랐는데.","JPN":"目を覚ました直後に見るのが、そなたの顔だとは思わなかった。","ENG":"Didn't expect to see you first thing when I opened my eyes.","TWN":"沒想到我睜開眼睛，看到的第一個竟然是你。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 여자애가 울고 불면서 기절한 당신을 업어왔어.","JPN":"あの女の子が泣きながらお前を負ぶってきた。","ENG":"That girl dragged you back here, bawling her eyes out.","TWN":"那小女孩哭哭啼啼地把昏迷的你揹回來的。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"별로 큰 상처를 입은 것도 아니던데, 원래 그렇게 엄살이 심한 편인가?","JPN":"大した怪我でもなさそうだが、元々大げさなタイプなのか？","ENG":"You didn't even look that badly hurt. Do you always make such a fuss?","TWN":"我看你也沒有傷得很重，你本來就這麼嬌弱嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…빈혈 같은 걸세. 못난 모습을 보였군.","JPN":"……貧血のようなものだ。無様な姿を見せてしまった。","ENG":"…Just a bit of dizziness. Shameful display, I admit.","TWN":"…應該是貧血。讓你看到這麼狼狽的一面。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 녀석은 자기 탓이라고 했어. 당신의 발명품을 지키려고 무리를 했다던데.","JPN":"あの子は自分のせいだと言っていた。お前の発明品を守るために無茶をしたらしいが。","ENG":"She kept saying it was her fault. Said she pushed herself too hard trying to protect your invention.","TWN":"那小女孩說都是她的錯。為了保護你的發明品，高估了自己的能力。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"목숨을 걸어야 할 정도로 비싼 물건인가 봐?","JPN":"命をかけるほど高価なものなのか？","ENG":"Must be worth risking a life for, huh?","TWN":"那東西很貴嗎，值得用性命去守護？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"비싸다 한들… 목숨에 비할 바 있겠나.","JPN":"いくら高くとも……命と比べられるものではない。","ENG":"No matter how valuable it is… it's not worth a life.","TWN":"再貴…也比不上性命。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"어디까지나 사고였을 뿐이야.","JPN":"これはあくまで事故だ。","ENG":"It was just an accident, nothing more.","TWN":"這只是一場意外。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"미안하지만 급히 확인할 것이 생겼어. 도시로 가는 건 나중으로 미뤄도 괜찮겠나?","JPN":"すまないが急に確かめねばならんことができた。都市に行くのは待ってもらえんか。","ENG":"Sorry, but there's something I need to check. Mind if we postpone the trip to the city?","TWN":"抱歉，我突然有急事要確認。去城市的事，可以先延後嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그렇게 해. 당신들 일보다 급한 용무는 아닐 테니까.","JPN":"ああ。お前たちほど急いでいるわけじゃないからな。","ENG":"Do as you please. My business can wait.","TWN":"沒問題。你們的事比較急。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그럼 나중에 돌아오지.","JPN":"では、後ほど戻ってこよう。","ENG":"I'll be back later.","TWN":"那我之後會回來。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아, 사부.","JPN":"あ、師匠。","ENG":"Oh, Master.","TWN":"師父。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"벌써 일어났어? 좀 더 누워있지.","JPN":"大丈夫？　もうちょっと寝てていいのに。","ENG":"You're up already? You should've rested a bit more.","TWN":"你已經醒啦？再多躺一下吧。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"어떻게 됐지, 앤디?","JPN":"アンディー、どうだ？","ENG":"How's it looking, Andy?","TWN":"怎麼樣了，安狄？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"별 이상은 없나?","JPN":"異常はないか？","ENG":"Nothing strange?","TWN":"沒什麼異常吧？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"응, 그야 난 사부가 구해준 덕분에…","JPN":"うん、私は師匠が助けてくれたから……","ENG":"Oh, I'm fine thanks to you, Mas–","TWN":"嗯，多虧師父出手相救…"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"장치 말일세. 에너지 충전의 상태는 어떻지?","JPN":"装置のことだ。エネルギー充電の状態は？","ENG":"I meant the device. What's the energy level?","TWN":"我是說裝置，能量儲存的狀態怎麼樣？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"어…? <color=#ffd34c>과.위.장</color>말야?","JPN":"え……？　<color=#ffd34c>過向装</color>のこと？","ENG":"Huh? You mean the <color=#ffd34c>DTP</color>?","TWN":"蛤…？你說<color=#ffd34c>回裝置</color>嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그건 모르겠어. 쓰러진 사부를 데리고 바로 돌아왔거든.","JPN":"そっちはまだ確かめてない。倒れた師匠を連れてすぐ戻ってきちゃったし。","ENG":"No idea. I rushed back with you the moment you collapsed.","TWN":"我不知道。師父暈倒後，我就趕快把你揹回來。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그보다 배고프지? 내가 죽 만들어왔는데…","JPN":"それよりお腹空いてない？　おかゆ作ったけど……","ENG":"But aren't you hungry? I made you some porridge…","TWN":"先不說這個了。你餓了吧？我有煮粥…"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};